FONT_LIGHT_B64   = ""

# Write fonts to temp files so reportlab can load them
import tempfile as _tf
def _write_font(b64_data):
    tmp = _tf.NamedTemporaryFile(suffix=".ttf", delete=False)
    tmp.write(base64.b64decode(b64_data)); tmp.flush(); return tmp.name

_FONT_REGULAR_PATH = _write_font(FONT_REGULAR_B64)
_FONT_BOLD_PATH    = _write_font(FONT_BOLD_B64)
_FONT_ITALIC_PATH  = _write_font(FONT_ITALIC_B64)
_FONT_MEDIUM_PATH  = _write_font(FONT_MEDIUM_B64)
_FONT_LIGHT_PATH   = _write_font(FONT_LIGHT_B64)

pdfmetrics.registerFont(TTFont("Poppins",        _FONT_REGULAR_PATH))
pdfmetrics.registerFont(TTFont("Poppins-Bold",   _FONT_BOLD_PATH))
pdfmetrics.registerFont(TTFont("Poppins-Italic", _FONT_ITALIC_PATH))
pdfmetrics.registerFont(TTFont("Poppins-Medium", _FONT_MEDIUM_PATH))
pdfmetrics.registerFont(TTFont("Poppins-Light",  _FONT_LIGHT_PATH))
registerFontFamily("Poppins", normal="Poppins", bold="Poppins-Bold", italic="Poppins-Italic", boldItalic="Poppins-Bold")

